//! `--config none|<path>` — `.vc-config.toml` write override.
//! See [options_flags](README.md) for shared architecture.

use std::path::PathBuf;

use clap::Args;

/// Parsed `--config` value.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum ConfigKind {
    /// Skip writing entirely (`--config none`).
    None,
    /// User-provided file (`--config <path>`).
    Path(PathBuf),
}

/// Parse `--config`; `""` returns `default`, `"none"` returns
/// `ConfigKind::None`, anything else is a path.
pub fn parse_config_kind(s: &str, default: ConfigKind) -> ConfigKind {
    match s {
        "" => default,
        "none" => ConfigKind::None,
        _ => ConfigKind::Path(PathBuf::from(s)),
    }
}

/// `--config none|<path>` leaf (Option — non-boolean domain) —
/// see [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct ConfigOption {
    /// Override the canned `.vc-config.toml` write.
    ///
    /// - Absent: write the canned `.vc-config.toml`.
    /// - `--config none`: skip writing entirely.
    /// - `--config <path>`: copy `<path>` to `.vc-config.toml`
    ///   (bytewise; no schema validation).
    #[arg(long = "config", value_name = "none|PATH", verbatim_doc_comment)]
    pub raw: Option<String>,
}

impl ConfigOption {
    /// Resolve `raw` against `default`; `None` when flag absent.
    pub fn resolve(&self, default: ConfigKind) -> Option<ConfigKind> {
        self.raw.as_deref().map(|s| parse_config_kind(s, default))
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Stand-in default for tests where the default branch isn't
    /// the one being exercised.
    fn test_default() -> ConfigKind {
        ConfigKind::None
    }

    #[test]
    fn keyword_none() {
        assert_eq!(parse_config_kind("none", test_default()), ConfigKind::None,);
    }

    #[test]
    fn relative_path() {
        assert_eq!(
            parse_config_kind("./my-config.toml", test_default()),
            ConfigKind::Path(PathBuf::from("./my-config.toml")),
        );
    }

    #[test]
    fn absolute_path() {
        assert_eq!(
            parse_config_kind("/etc/vc-x1/config.toml", test_default()),
            ConfigKind::Path(PathBuf::from("/etc/vc-x1/config.toml")),
        );
    }

    #[test]
    fn home_relative_path() {
        assert_eq!(
            parse_config_kind("~/configs/foo.toml", test_default()),
            ConfigKind::Path(PathBuf::from("~/configs/foo.toml")),
        );
    }

    #[test]
    fn bare_filename_treated_as_path() {
        assert_eq!(
            parse_config_kind("foo.toml", test_default()),
            ConfigKind::Path(PathBuf::from("foo.toml")),
        );
    }

    #[test]
    fn empty_returns_default() {
        let default = ConfigKind::Path(PathBuf::from("/canned/init-por.toml"));
        assert_eq!(parse_config_kind("", default.clone()), default);
    }

    #[test]
    fn empty_default_can_be_none() {
        assert_eq!(parse_config_kind("", ConfigKind::None), ConfigKind::None,);
    }

    #[test]
    fn config_option_resolve_absent() {
        let flag = ConfigOption { raw: None };
        assert_eq!(flag.resolve(test_default()), None);
    }

    #[test]
    fn config_option_resolve_explicit_none() {
        let flag = ConfigOption {
            raw: Some("none".to_string()),
        };
        assert_eq!(flag.resolve(test_default()), Some(ConfigKind::None));
    }

    #[test]
    fn config_option_resolve_path() {
        let flag = ConfigOption {
            raw: Some("/etc/foo.toml".to_string()),
        };
        assert_eq!(
            flag.resolve(test_default()),
            Some(ConfigKind::Path(PathBuf::from("/etc/foo.toml"))),
        );
    }

    #[test]
    fn config_option_resolve_empty_uses_default() {
        let default = ConfigKind::Path(PathBuf::from("/canned/init-por.toml"));
        let flag = ConfigOption {
            raw: Some(String::new()),
        };
        assert_eq!(flag.resolve(default.clone()), Some(default));
    }
}

//! `--repo` — pick a repo target via the user-config
//! account chain. See [options_flags](README.md) for shared
//! architecture.

use clap::Args;

use crate::config::RepoSelector;

/// Parse the `--repo` value into a `config::RepoSelector`.
///
/// - `<cat>` → `RepoSelector { category, value: None }`.
/// - `<cat>=<val>` → `RepoSelector { category, value: Some(val) }`.
/// - Empty input, empty category, or empty value (after `=`)
///   errors.
pub fn parse_repo_arg(s: &str) -> Result<RepoSelector, String> {
    let s = s.trim();
    if s.is_empty() {
        return Err("--repo: value is empty".into());
    }
    match s.split_once('=') {
        Some((cat, val)) => {
            let cat = cat.trim();
            let val = val.trim();
            if cat.is_empty() {
                return Err(format!("--repo: missing category in '{s}'"));
            }
            if val.is_empty() {
                return Err(format!("--repo: empty value in '{s}'"));
            }
            Ok(RepoSelector {
                category: cat.to_string(),
                value: Some(val.to_string()),
            })
        }
        None => Ok(RepoSelector {
            category: s.to_string(),
            value: None,
        }),
    }
}

/// `OptionParser` impl for `--repo` (non-boolean domain).
/// Documentation-level — consumers can use either
/// `parse_repo_arg` directly or `RepoParser::parse`.
pub struct RepoParser;

impl super::OptionParser for RepoParser {
    type Value = RepoSelector;

    fn parse(s: &str) -> Result<Self::Value, String> {
        parse_repo_arg(s)
    }
}

/// `--repo` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct RepoOption {
    /// Repo target — `<cat>` or `<cat>=<val>`.
    ///
    /// - `<cat>` looks up the value via the account chain
    ///   in the user config.
    /// - `<cat>=<val>` uses the literal value, no config
    ///   lookup needed.
    /// - Specific category meanings (`remote`, `local`,
    ///   …) depend on the consumer subcommand.
    #[arg(
        long,
        value_name = "CAT[=VAL]",
        value_parser = parse_repo_arg,
        verbatim_doc_comment
    )]
    pub repo: Option<RepoSelector>,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn repo_arg_category_only() {
        let sel = parse_repo_arg("remote").unwrap();
        assert_eq!(sel.category, "remote");
        assert_eq!(sel.value, None);
    }

    #[test]
    fn repo_arg_category_and_value() {
        let sel = parse_repo_arg("local=/tmp/fixtures").unwrap();
        assert_eq!(sel.category, "local");
        assert_eq!(sel.value.as_deref(), Some("/tmp/fixtures"));
    }

    #[test]
    fn repo_arg_trims_whitespace() {
        let sel = parse_repo_arg("  remote = git@github.com:foo  ").unwrap();
        assert_eq!(sel.category, "remote");
        assert_eq!(sel.value.as_deref(), Some("git@github.com:foo"));
    }

    #[test]
    fn repo_arg_empty_errors() {
        let err = parse_repo_arg("").unwrap_err();
        assert!(err.contains("empty"), "got: {err}");
    }

    #[test]
    fn repo_arg_missing_category_errors() {
        let err = parse_repo_arg("=foo").unwrap_err();
        assert!(err.contains("missing category"), "got: {err}");
    }

    #[test]
    fn repo_arg_empty_value_errors() {
        let err = parse_repo_arg("remote=").unwrap_err();
        assert!(err.contains("empty value"), "got: {err}");
    }
}

//! `--use-template` — seed repos from template directories.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--use-template` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct UseTemplateOption {
    /// Seed repos from template directories.
    ///
    /// Value is `WORK[,BOT]`. Default bot path is `<CODE>.claude`
    /// (file-name concat, not path join — templates are siblings).
    ///
    /// - With `--scope=por`: only `WORK` is used; passing `,BOT`
    ///   is fatal (no bot side to seed).
    /// - Non-hidden contents copied recursively; hidden entries
    ///   (names starting with `.`) are skipped — init writes its
    ///   own hidden files.
    /// - If a copied tree has a `README.md`, its first line is
    ///   rewritten to `# <repo-name>`.
    #[arg(long, value_name = "WORK[,BOT]", verbatim_doc_comment)]
    pub use_template: Option<String>,
}

